// MARK: - Models

struct Stock: Identifiable, Codable, Hashable {
    let id = UUID() // For SwiftUI Identifiable protocol
    let symbol: String
    let name: String
    var currentPrice: Double
    var priceChange: Double? // Absolute change
    var percentChange: Double? // Percentage change

    private enum CodingKeys: String, CodingKey {
        case symbol, name, currentPrice, priceChange, percentChange
    }

    // Update prices and calculate changes
    mutating func updatePrice(newPrice: Double) {
        let oldPrice = self.currentPrice
        self.currentPrice = newPrice
        self.priceChange = newPrice - oldPrice
        if oldPrice != 0 {
            self.percentChange = (priceChange! / oldPrice) * 100
        } else {
            self.percentChange = 0
        }
    }
}

struct Trade: Identifiable, Codable {
    let id = UUID()
    let stockSymbol: String
    let tradeType: TradeType
    let quantity: Int
    let price: Double
    let timestamp: Date
}

enum TradeType: String, Codable {
    case buy = "Buy"
    case sell = "Sell"
}

struct PortfolioItem: Identifiable, Codable {
    let id = UUID()
    let stockSymbol: String
    var quantity: Int
    var averageCost: Double // Weighted average cost per share
}

struct UserAccount: Codable {
    var balance: Double
    var portfolio: [PortfolioItem]

    static let mock: UserAccount = UserAccount(balance: 10000.00, portfolio: [])

    // Helper to encode/decode to/from Data
    func save() {
        if let encoded = try? JSONEncoder().encode(self) {
            UserDefaults.standard.set(encoded, forKey: "userAccount")
        }
    }

    static func load() -> UserAccount {
        if let savedAccountData = UserDefaults.standard.data(forKey: "userAccount"),
           let decodedAccount = try? JSONDecoder().decode(UserAccount.self, from: savedAccountData) {
            return decodedAccount
        }
        return .mock // Return mock if nothing found
    }
}

// MARK: - API Service (Mock for Rapid Deployment)

class APIService: ObservableObject {
    @Published var stocks: [Stock] = []
    private var timer: AnyCancellable?

    init() {
        // Initialize with some mock stocks
        self.stocks = [
            Stock(symbol: "AAPL", name: "Apple Inc.", currentPrice: 170.00),
            Stock(symbol: "GOOG", name: "Alphabet Inc.", currentPrice: 1500.00),
            Stock(symbol: "MSFT", name: "Microsoft Corp.", currentPrice: 400.00),
            Stock(symbol: "AMZN", name: "Amazon.com Inc.", currentPrice: 180.00),
            Stock(symbol: "TSLA", name: "Tesla, Inc.", currentPrice: 200.00),
            Stock(symbol: "NVDA", name: "NVIDIA Corp.", currentPrice: 900.00),
            Stock(symbol: "SMCI", name: "Super Micro Computer, Inc.", currentPrice: 900.00)
        ]
        // Calculate initial changes
        for i in stocks.indices {
            stocks[i].updatePrice(newPrice: stocks[i].currentPrice)
        }

        // Simulate real-time price updates every 5 seconds
        timer = Timer.publish(every: 5.0, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                self?.updateRandomStockPrices()
            }
    }

    private func updateRandomStockPrices() {
        for i in stocks.indices {
            let currentPrice = stocks[i].currentPrice
            // Generate a random change between -2% and +2%
            let change = (Double.random(in: -0.02...0.02)) * currentPrice
            let newPrice = max(0.01, currentPrice + change) // Ensure price doesn't go below zero
            stocks[i].updatePrice(newPrice: newPrice)
        }
    }

    // In a real app, this would be an actual network call
    func fetchStocks() async throws -> [Stock] {
        // Simulate network delay
        try await Task.sleep(nanoseconds: 500_000_000)
        return stocks // Return current mock stocks
    }
}

// MARK: - View Models

class StockListViewModel: ObservableObject {
    @Published var stocks: [Stock] = []
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?

    private var apiService: APIService
    private var cancellables = Set<AnyCancellable>()

    init(apiService: APIService) {
        self.apiService = apiService
        setupBindings()
    }

    private func setupBindings() {
        apiService.$stocks
            .assign(to: \.stocks, on: self)
            .store(in: &cancellables)
    }

    func loadStocks() async {
        isLoading = true
        errorMessage = nil
        do {
            // The APIService already updates its own @Published stocks,
            // so this call primarily for initial setup or if we needed to
            // refresh from a real backend.
            _ = try await apiService.fetchStocks()
        } catch {
            errorMessage = "Failed to load stocks: \(error.localizedDescription)"
        }
        isLoading = false
    }
}

class StockDetailViewModel: ObservableObject {
    @Published var stock: Stock
    @Published var quantity: String = ""
    @Published var tradeMessage: String?
    @Published var tradeError: String?

    private var apiService: APIService
    private var accountManager: UserAccountManager

    init(stock: Stock, apiService: APIService, accountManager: UserAccountManager) {
        self.stock = stock
        self.apiService = apiService
        self.accountManager = accountManager

        // Update stock price if it changes in the APIService
        apiService.$stocks
            .compactMap { stocks in
                stocks.first { $0.symbol == stock.symbol }
            }
            .assign(to: \.stock, on: self)
            .store(in: &accountManager.cancellables) // Using accountManager's cancellables, could be its own
    }

    var totalCost: Double {
        guard let qty = Int(quantity), qty > 0 else { return 0 }
        return Double(qty) * stock.currentPrice
    }

    func executeTrade(type: TradeType) {
        tradeMessage = nil
        tradeError = nil

        guard let qty = Int(quantity), qty > 0 else {
            tradeError = "Please enter a valid quantity."
            return
        }

        accountManager.performTrade(
            stock: stock,
            quantity: qty,
            tradeType: type
        ) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let trade):
                    self?.tradeMessage = "\(trade.tradeType.rawValue) \(trade.quantity) shares of \(trade.stockSymbol) for $\(trade.price * Double(trade.quantity), specifier: "%.2f")"
                    self?.quantity = "" // Clear quantity after successful trade
                case .failure(let error):
                    self?.tradeError = error.localizedDescription
                }
            }
        }
    }
}

enum AccountError: LocalizedError {
    case insufficientFunds
    case insufficientShares(symbol: String, available: Int, requested: Int)
    case invalidQuantity

    var errorDescription: String? {
        switch self {
        case .insufficientFunds:
            return "Insufficient funds to complete this purchase."
        case .insufficientShares(let symbol, let available, let requested):
            return "Insufficient shares of \(symbol). You only own \(available) but tried to sell \(requested)."
        case .invalidQuantity:
            return "Trade quantity must be a positive integer."
        }
    }
}

class UserAccountManager: ObservableObject {
    @Published var account: UserAccount {
        didSet {
            account.save() // Persist changes
        }
    }
    var cancellables = Set<AnyCancellable>() // For APIService bindings if needed later

    init() {
        self.account = UserAccount.load()
    }

    func performTrade(stock: Stock, quantity: Int, tradeType: TradeType, completion: @escaping (Result<Trade, AccountError>) -> Void) {
        guard quantity > 0 else {
            completion(.failure(.invalidQuantity))
            return
        }

        let totalTradeValue = stock.currentPrice * Double(quantity)

        switch tradeType {
        case .buy:
            guard account.balance >= totalTradeValue else {
                completion(.failure(.insufficientFunds))
                return
            }
            account.balance -= totalTradeValue

            if let index = account.portfolio.firstIndex(where: { $0.stockSymbol == stock.symbol }) {
                // Update existing item
                let currentItem = account.portfolio[index]
                let newTotalCost = (currentItem.averageCost * Double(currentItem.quantity)) + totalTradeValue
                let newTotalQuantity = currentItem.quantity + quantity
                account.portfolio[index].averageCost = newTotalCost / Double(newTotalQuantity)
                account.portfolio[index].quantity = newTotalQuantity
            } else {
                // Add new item
                account.portfolio.append(PortfolioItem(stockSymbol: stock.symbol, quantity: quantity, averageCost: stock.currentPrice))
            }

        case .sell:
            guard let index = account.portfolio.firstIndex(where: { $0.stockSymbol == stock.symbol }) else {
                completion(.failure(.insufficientShares(symbol: stock.symbol, available: 0, requested: quantity)))
                return
            }

            let portfolioItem = account.portfolio[index]
            guard portfolioItem.quantity >= quantity else {
                completion(.failure(.insufficientShares(symbol: stock.symbol, available: portfolioItem.quantity, requested: quantity)))
                return
            }

            account.balance += totalTradeValue

            if portfolioItem.quantity == quantity {
                // Sell all shares
                account.portfolio.remove(at: index)
            } else {
                // Sell some shares
                account.portfolio[index].quantity -= quantity
            }
        }

        let trade = Trade(stockSymbol: stock.symbol, tradeType: tradeType, quantity: quantity, price: stock.currentPrice, timestamp: Date())
        completion(.success(trade))
    }
}

