struct PortfolioView: View {
    @EnvironmentObject var accountManager: UserAccountManager
    @EnvironmentObject var apiService: APIService // To get current stock prices for portfolio value

    var totalPortfolioValue: Double {
        accountManager.account.portfolio.reduce(0) { total, item in
            if let stock = apiService.stocks.first(where: { $0.symbol == item.stockSymbol }) {
                return total + (stock.currentPrice * Double(item.quantity))
            }
            return total
        }
    }

    var totalNetWorth: Double {
        accountManager.account.balance + totalPortfolioValue
    }

    var body: some View {
        NavigationView {
            List {
                Section("Account Summary") {
                    HStack {
                        Text("Cash Balance:")
                        Spacer()
                        Text(accountManager.account.balance, format: .currency(code: "USD"))
                            .font(.headline)
                    }
                    HStack {
                        Text("Portfolio Value:")
                        Spacer()
                        Text(totalPortfolioValue, format: .currency(code: "USD"))
                            .font(.headline)
                    }
                    HStack {
                        Text("Total Net Worth:")
                        Spacer()
                        Text(totalNetWorth, format: .currency(code: "USD"))
                            .font(.largeTitle)
                            .fontWeight(.bold)
                    }
                }

                Section("Your Holdings") {
                    if accountManager.account.portfolio.isEmpty {
                        Text("You don't own any stocks yet. Start trading!")
                            .foregroundColor(.gray)
                    } else {
                        ForEach(accountManager.account.portfolio) { item in
                            if let stock = apiService.stocks.first(where: { $0.symbol == item.stockSymbol }) {
                                PortfolioRowView(portfolioItem: item, currentStockPrice: stock.currentPrice)
                            }
                        }
                    }
                }
            }
            .navigationTitle("Portfolio")
        }
    }
}

struct PortfolioRowView: View {
    let portfolioItem: PortfolioItem
    let currentStockPrice: Double

    var currentValue: Double {
        currentStockPrice * Double(portfolioItem.quantity)
    }

    var gainLoss: Double {
        currentValue - (portfolioItem.averageCost * Double(portfolioItem.quantity))
    }

    var gainLossPercent: Double {
        let initialValue = portfolioItem.averageCost * Double(portfolioItem.quantity)
        if initialValue == 0 { return 0 }
        return (gainLoss / initialValue) * 100
    }

    var body: some View {
        HStack {
            VStack(alignment: .leading) {
                Text(portfolioItem.stockSymbol)
                    .font(.headline)
                Text("\(portfolioItem.quantity) shares @ \(portfolioItem.averageCost, format: .currency(code: "USD")) avg.")
                    .font(.subheadline)
                    .foregroundColor(.gray)
            }
            Spacer()
            VStack(alignment: .trailing) {
                Text(currentValue, format: .currency(code: "USD"))
                    .font(.headline)
                HStack(spacing: 4) {
                    Image(systemName: gainLoss >= 0 ? "arrow.up.right" : "arrow.down.right")
                        .font(.caption)
                    Text("\(gainLoss, format: .currency(code: "USD")) (\(gainLossPercent, format: .percent.precision(.fractionLength(2))))")
                }
                .font(.subheadline)
                .foregroundColor(gainLoss >= 0 ? .green : .red)
            }
        }
    }
}

